#include <iostream>
#include <fstream>
#include <string>
#include <vector>
#include <cstring>

struct SaveHeader {
    char magic[8];      // "SAVEGAME"
    int version;
    int playerCount;
    long long timestamp;
};

struct PlayerData {
    char name[32];
    int health;
    int attack;
    int defense;
    int level;
    float experience;
    bool isAlive;
};

struct SaveFile {
    SaveHeader header;
    std::vector<PlayerData> players;
};

void writeBinarySave(const SaveFile& save, const std::string& filename) {
    std::ofstream file(filename, std::ios::binary);

    if (!file.is_open()) {
        std::cout << "❌ Failed to open file for writing!" << std::endl;
        return;
    }

    // Write header
    file.write(reinterpret_cast<const char*>(&save.header), sizeof(SaveHeader));

    // Write player data
    for (const auto& player : save.players) {
        file.write(reinterpret_cast<const char*>(&player), sizeof(PlayerData));
    }

    file.close();
    std::cout << "✅ Binary save written to " << filename << std::endl;
}

SaveFile readBinarySave(const std::string& filename) {
    SaveFile save;
    std::ifstream file(filename, std::ios::binary);

    if (!file.is_open()) {
        std::cout << "❌ Failed to open file for reading!" << std::endl;
        return save;
    }

    // Read header
    file.read(reinterpret_cast<char*>(&save.header), sizeof(SaveHeader));

    // Check magic
    if (strncmp(save.header.magic, "SAVEGAME", 8) != 0) {
        std::cout << "❌ Invalid save file!" << std::endl;
        file.close();
        return save;
    }

    // Read players
    save.players.resize(save.header.playerCount);
    for (int i = 0; i < save.header.playerCount; i++) {
        file.read(reinterpret_cast<char*>(&save.players[i]), sizeof(PlayerData));
    }

    file.close();
    std::cout << "✅ Binary save loaded from " << filename << std::endl;

    return save;
}

void displaySave(const SaveFile& save) {
    std::cout << "\n=== Save File ===" << std::endl;
    std::cout << "Magic: " << save.header.magic << std::endl;
    std::cout << "Version: " << save.header.version << std::endl;
    std::cout << "Player Count: " << save.header.playerCount << std::endl;
    std::cout << "Timestamp: " << save.header.timestamp << std::endl;

    std::cout << "\n--- Players ---" << std::endl;
    for (const auto& p : save.players) {
        std::cout << "  Name: " << p.name << std::endl;
        std::cout << "    Health: " << p.health << std::endl;
        std::cout << "    Attack: " << p.attack << std::endl;
        std::cout << "    Defense: " << p.defense << std::endl;
        std::cout << "    Level: " << p.level << std::endl;
        std::cout << "    Experience: " << p.experience << std::endl;
        std::cout << "    Alive: " << (p.isAlive ? "Yes" : "No") << std::endl;
    }
}

int main() {
    std::cout << "=== Binary File I/O — Save Files ===" << std::endl;

    // 1. Create save data
    SaveFile save;

    // Header
    strncpy(save.header.magic, "SAVEGAME", 8);
    save.header.version = 1;
    save.header.playerCount = 2;
    save.header.timestamp = 1234567890LL;

    // Players
    PlayerData p1;
    strncpy(p1.name, "Hero", 31);
    p1.health = 100;
    p1.attack = 20;
    p1.defense = 15;
    p1.level = 5;
    p1.experience = 250.5f;
    p1.isAlive = true;
    save.players.push_back(p1);

    PlayerData p2;
    strncpy(p2.name, "Aragorn", 31);
    p2.health = 120;
    p2.attack = 25;
    p2.defense = 18;
    p2.level = 6;
    p2.experience = 300.0f;
    p2.isAlive = true;
    save.players.push_back(p2);

    // 2. Write binary save
    writeBinarySave(save, "game.bin");

    // 3. Read binary save
    SaveFile loaded = readBinarySave("game.bin");
    displaySave(loaded);

    // 4. Binary vs Text comparison
    std::cout << "\n--- Binary vs Text ---" << std::endl;
    std::cout << "Binary saves:" << std::endl;
    std::cout << "  ✅ Smaller file size" << std::endl;
    std::cout << "  ✅ Faster read/write" << std::endl;
    std::cout << "  ✅ Preserves data exactly" << std::endl;
    std::cout << "  ❌ Not human-readable" << std::endl;
    std::cout << "\nText saves:" << std::endl;
    std::cout << "  ✅ Human-readable" << std::endl;
    std::cout << "  ✅ Easy to edit" << std::endl;
    std::cout << "  ❌ Larger file size" << std::endl;
    std::cout << "  ❌ Slower read/write" << std::endl;

    return 0;
}

