#include <iostream>
#include <fstream>
#include <cstring>

struct EnemyData {
    char name[20];
    int health;
    int attack;
    bool isBoss;
};

int main() {
    std::cout << "=== Binary Enemy Data ===" << std::endl;

    // Create enemies
    EnemyData enemies[3];
    strcpy(enemies[0].name, "Goblin");
    enemies[0].health = 30;
    enemies[0].attack = 8;
    enemies[0].isBoss = false;

    strcpy(enemies[1].name, "Orc");
    enemies[1].health = 50;
    enemies[1].attack = 12;
    enemies[1].isBoss = false;

    strcpy(enemies[2].name, "Dragon");
    enemies[2].health = 200;
    enemies[2].attack = 25;
    enemies[2].isBoss = true;

    // Write binary
    std::ofstream outFile("enemies.bin", std::ios::binary);
    if (outFile.is_open()) {
        outFile.write(reinterpret_cast<const char*>(enemies), sizeof(EnemyData) * 3);
        outFile.close();
        std::cout << "✅ Enemies saved to enemies.bin" << std::endl;
    }

    // Read binary
    EnemyData loaded[3];
    std::ifstream inFile("enemies.bin", std::ios::binary);
    if (inFile.is_open()) {
        inFile.read(reinterpret_cast<char*>(loaded), sizeof(EnemyData) * 3);
        inFile.close();
        std::cout << "✅ Enemies loaded from enemies.bin" << std::endl;
    }

    // Display
    std::cout << "\n=== Loaded Enemies ===" << std::endl;
    for (int i = 0; i < 3; i++) {
        std::cout << "Enemy " << i + 1 << ":" << std::endl;
        std::cout << "  Name: " << loaded[i].name << std::endl;
        std::cout << "  Health: " << loaded[i].health << std::endl;
        std::cout << "  Attack: " << loaded[i].attack << std::endl;
        std::cout << "  Boss: " << (loaded[i].isBoss ? "Yes" : "No") << std::endl;
    }

    return 0;
}
